let a = UIView(), b = UIView()
[a, b].forEach {
  $0.translatesAutoresizingMaskIntoConstraints = false
  view.addSubview($0)
}

// Anchors — modern API
NSLayoutConstraint.activate([
  a.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 16),
  a.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
  a.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16),
  a.heightAnchor.constraint(equalToConstant: 80),

  b.topAnchor.constraint(equalTo: a.bottomAnchor, constant: 12),
  b.leadingAnchor.constraint(equalTo: a.leadingAnchor),
  b.trailingAnchor.constraint(equalTo: a.trailingAnchor),
  b.heightAnchor.constraint(equalTo: a.heightAnchor),
])

// Frame-based for comparison — does NOT adapt
let old = UIView(frame: CGRect(x: 16, y: 100, width: view.bounds.width - 32, height: 80))
// ... and you'd have to redo this in viewDidLayoutSubviews on rotation, etc.

// Common pitfalls
// 1) Forgetting translatesAutoresizingMaskIntoConstraints = false — Auto Layout fights
//    autoresizing mask constraints and you get "unable to satisfy".
// 2) Animating layout changes — change constants, then call view.layoutIfNeeded inside
//    UIView.animate to animate to the new positions.

let title = UILabel(); title.text = "Long article title that wraps"
let badge = UILabel(); badge.text = "NEW"

// Title should yield space; badge should hold its size
title.setContentHuggingPriority(.defaultLow, for: .horizontal)
title.setContentCompressionResistancePriority(.defaultLow - 1, for: .horizontal)

badge.setContentHuggingPriority(.required, for: .horizontal)
badge.setContentCompressionResistancePriority(.required, for: .horizontal)

// In a stack
let row = UIStackView(arrangedSubviews: [title, badge])
row.axis = .horizontal
row.spacing = 8
row.alignment = .center

// Custom view with intrinsic size — override
class Pill: UIView {
  let label = UILabel()
  override var intrinsicContentSize: CGSize {
    let s = label.intrinsicContentSize
    return CGSize(width: s.width + 24, height: s.height + 8)
  }
  override init(frame: CGRect) {
    super.init(frame: frame)
    addSubview(label)
  }
  required init?(coder: NSCoder) { fatalError() }
}

// Force re-measurement when content changes
func setText(_ s: String) {
  label.text = s
  invalidateIntrinsicContentSize()
}

// Vertical stack of content
let content = UIStackView(arrangedSubviews: [
  titleLabel,
  subtitleLabel,
  metadataRow,
])
content.axis = .vertical
content.spacing = 8
content.alignment = .leading

// metadataRow itself is a horizontal stack
let metadataRow = UIStackView(arrangedSubviews: [authorLabel, dotLabel, dateLabel])
metadataRow.axis = .horizontal
metadataRow.spacing = 4

// Add to view + constrain only the outer container
view.addSubview(content)
content.translatesAutoresizingMaskIntoConstraints = false
NSLayoutConstraint.activate([
  content.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
  content.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16),
  content.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 16),
])

// Hide a row — stack collapses the gap
subtitleLabel.isHidden = true

// Custom spacing after a specific child (iOS 11+)
content.setCustomSpacing(20, after: titleLabel)

// .fillEqually distributes children evenly along the axis
let tabs = UIStackView(arrangedSubviews: [tab1, tab2, tab3])
tabs.distribution = .fillEqually

// Pin a button to the bottom safe area (above the home indicator)
view.addSubview(button)
button.translatesAutoresizingMaskIntoConstraints = false
NSLayoutConstraint.activate([
  button.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
  button.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16),
  button.bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -8),
  button.heightAnchor.constraint(equalToConstant: 50),
])

// Push content down past a custom banner the VC adds
additionalSafeAreaInsets = UIEdgeInsets(top: 56, left: 0, bottom: 0, right: 0)

// React to insets change (rare — rotation / multitasking)
override func safeAreaInsetsDidChange() {
  super.safeAreaInsetsDidChange()
  // adjust custom layouts that read view.safeAreaInsets directly
}

// Edges for extension — old-style API
edgesForExtendedLayout = []  // don't extend under nav/tab bars
extendedLayoutIncludesOpaqueBars = false

// In SwiftUI you reach for safe area via .ignoresSafeArea() and the SafeAreaRegions
// argument to opt into / out of which insets to ignore.

// Name constraints for readable logs
let c = button.bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -8)
c.identifier = "buttonBottom"
c.isActive = true

// Make an optional constraint break gracefully
let preferred = label.widthAnchor.constraint(equalToConstant: 200)
preferred.priority = .defaultHigh    // 750 — broken before required (1000)
preferred.isActive = true

// Detect ambiguous layout in dev
#if DEBUG
DispatchQueue.main.async {
  if view.hasAmbiguousLayout { view.exerciseAmbiguityInLayout() }
}
#endif

// Symbolic breakpoint setup (Xcode):
// 1. Breakpoints navigator → +Symbolic Breakpoint
// 2. Symbol: UIViewAlertForUnsatisfiableConstraints
// When triggered, you can `po [view recursiveDescription]` in the LLDB console.

// Animating constraint changes — must call layoutIfNeeded inside the animation block
leadingConstraint.constant = 100
UIView.animate(withDuration: 0.3) {
  self.view.layoutIfNeeded()
}

// Animate by changing constraint constants
leadingConstraint.constant = 100
view.setNeedsLayout()
UIView.animate(withDuration: 0.3) {
  view.layoutIfNeeded()           // forces the new layout to apply inside the animation
}

// Custom subview layout — override layoutSubviews
class GradientView: UIView {
  let gradient = CAGradientLayer()
  override init(frame: CGRect) {
    super.init(frame: frame)
    layer.addSublayer(gradient)
  }
  required init?(coder: NSCoder) { fatalError() }
  override func layoutSubviews() {
    super.layoutSubviews()
    gradient.frame = bounds // keep gradient sized with the view
  }
}

// setNeedsLayout vs layoutIfNeeded — pick by intent
func onContentChanged() {
  contentLabel.text = "..."
  setNeedsLayout()         // schedule a relayout
  // layoutIfNeeded() — only call if you need the new frames RIGHT NOW (e.g. in animation block)
}

// Don't call layoutSubviews directly — call setNeedsLayout / layoutIfNeeded.
